VALUES
  ('cpa-moex-01451', 'cpa', 'cpa-moex-102-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲公司20X1年底承租設備一部，租期3年，租金約定為每年底支付$200,000，若此筆租賃係屬融資 租賃性質，下列有關此筆交易對甲公司20X1年底財務報表分析影響之描述，何者正確？', '["負債比率減少、流動比率不變", "固定資產週轉率增加、負債比率增加", "股東權益報酬率減少、固定資產週轉率減少", "股東權益報酬率不變、流動比率減少"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "6d4bb59e61f3", "answer_pdf_sha1": "ad30222b6792", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01452', 'cpa', 'cpa-moex-102-78566e18', 'sub-cpa-01', NULL, 'single_choice', '乙公司決定自20X3年年初將存貨成本公式由先進先出法改為加權平均法，但報稅仍維持採用先進 先出法，該公司20X2年及20X3年期末存貨之金額如下： 20X2年 20X3年 先進先出法 $3,600,000 $3,100,000 加權平均法 3,750,000 3,230,000 若所得稅率為20%，則20X3年年初改變會計政策之分錄應為：', '["借記：遞延所得稅資產30,000", "貸記：遞延所得稅負債30,000", "貸記：遞延所得稅資產26,000", "借記：遞延所得稅負債26,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "6d4bb59e61f3", "answer_pdf_sha1": "ad30222b6792", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01453', 'cpa', 'cpa-moex-102-78566e18', 'sub-cpa-01', NULL, 'single_choice', '20X5年初甲公司以$5,000,000買入一具輻射性設備，耐用年限為3年，無殘值，採直線法折舊。根 據法令規定，該設備3年後須委請專業機構予以拆卸處理，估計3年後須花$500,000拆卸處理費， 該公司折現率為 10%。甲公司於 20X7 年底，以$520,000 請專業機構移除該設備，並認列$520,000 處分設備損失。若20X7年甲公司原列報綜合淨利為$600,000，則20X7年正確綜合淨利應為：', '["$474,780", "$580,000", "$600,000", "$929,325"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "6d4bb59e61f3", "answer_pdf_sha1": "ad30222b6792", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01454', 'cpa', 'cpa-moex-102-78566e18', 'sub-cpa-01', NULL, 'single_choice', '大河公司採確定福利計畫，20X1年底福利計畫相關資料如下： 確定福利義務現值 $20,000,000 計畫資產公允價值 12,000,000 前期服務成本未攤銷數 6,000,000 精算利益未攤銷數 5,000,000 應計退休金負債 7,000,000 大河公司於20X2年初縮小營業規模，預期將顯著減少眾多員工未來服務之退休金，因而減少確定福 利義務現值$5,000,000，大河公司處理此一事項，對應計退休金負債之影響為何？', '["應計退休金負債減少$5,000,000", "應計退休金負債減少$4,750,000", "應計退休金負債減少$1,750,000", "應計退休金負債無增減"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "6d4bb59e61f3", "answer_pdf_sha1": "ad30222b6792", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01455', 'cpa', 'cpa-moex-102-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲公司對其員工提供一項退休計畫，對50歲仍在職且已工作15年者，或於65歲仍在職者，均 支付$2,000,000之一次性退休福利。針對此項計畫之會計處理，下列敘述何者正確（暫不考慮現 值之效果）？', '["企業對於35歲以前加入之員工，其在35歲以前之服務並無須認列相關負債", "企業對於50歲始加入之員工，其每年所應認列之負債與於45歲始加入之員工，其每年所應認列 之負債係相同的", "僅", "正確"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "6d4bb59e61f3", "answer_pdf_sha1": "ad30222b6792", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01456', 'cpa', 'cpa-moex-102-78566e18', 'sub-cpa-01', NULL, 'single_choice', '承德公司於20X1年初成立，財務會計對於分期收款銷貨按普通銷貨法認列收入，申報所得稅時則採 毛利百分比法。開業前四年之分期收款銷貨毛利資料如下： 年度 普通銷貨法 毛利百分比法 20X1 $1,000,000 $ 600,000 20X2 2,000,000 1,400,000 20X3 1,000,000 1,200,000 20X4 1,500,000 1,800,000 各年度適用稅率皆為25%，無其他暫時性差異。則承德公司20X3年度之損益表中，列於所得稅費用 項下之遞延所得稅為：', '["遞延所得稅費用$50,000", "遞延所得稅利益$50,000", "遞延所得稅費用$200,000", "遞延所得稅利益$200,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "6d4bb59e61f3", "answer_pdf_sha1": "ad30222b6792", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01457', 'cpa', 'cpa-moex-102-78566e18', 'sub-cpa-01', NULL, 'single_choice', '中壢公司於期初設立，期末調整後試算表中應收帳款餘額100萬元，備抵呆帳餘額5萬元。稅務上 備抵呆帳餘額以應收帳款餘額百分之一為限。該應收帳款之課稅基礎為：', '["94萬元", "95萬元", "99萬元", "100萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "6d4bb59e61f3", "answer_pdf_sha1": "ad30222b6792", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01458', 'cpa', 'cpa-moex-102-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '下列何者屬於員工分紅制度中所稱之員工？', '["董事長", "監察人", "經理人", "董事"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "3ad65ff272ea", "answer_pdf_sha1": "219504eff4d3", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公司法、證券交易法與商業會計法", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01459', 'cpa', 'cpa-moex-102-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '天下股份有限公司之章程除記載經營電腦遊戲軟體開發及銷售業務外，尚記載「本公司得經營其他合法 事業」，請問下列事業項目，何者為天下股份有限公司不得經營之項目？', '["販賣文具及電腦零配件", "經營存款業務", "經營電腦維修業務", "經營泡沫紅茶業務"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "3ad65ff272ea", "answer_pdf_sha1": "219504eff4d3", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公司法、證券交易法與商業會計法", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01460', 'cpa', 'cpa-moex-102-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '股份有限公司進行分割者，其存續公司或新設之公司以何種公司為限？', '["無限公司", "股份有限公司", "有限公司", "無限制"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "3ad65ff272ea", "answer_pdf_sha1": "219504eff4d3", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公司法、證券交易法與商業會計法", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL)
